mapper.select:
SELECT category AS name, SUM(emission) AS value FROM carbonpoint WHERE year = #{year}
AND quarter = #{quarter}
GROUP BY category

SELECT year || '-' || quarter AS name, total_emission AS value
FROM (
    SELECT year, quarter, SUM(emission) AS total_emission
    FROM carbonpoint



                year BETWEEN #{yearStart} AND #{yearEnd}


                year = #{yearStart}



            AND category = #{category}


    GROUP BY year, quarter
) t
ORDER BY year, quarter
